using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Gestor central dos efeitos temporários dos itens consumíveis aplicados
/// directamente ao PLAYER (Tarefa "Itens Consumíveis"):
///
/// - Escudo (Casca Serenna) — ver <see cref="TryConsumeShield"/>, consumido em
///   PlayerCombat.TryDamagePlayer.
/// - Velocidade (Orvalho Veloz) — usa PlayerMotor2D.SetSpeedMultiplier.
/// - Invisibilidade (Pó Dourado) — ver <see cref="IsInvisible"/>, consultado por
///   EnemyDetection.
/// - Regeneração (Néctar Verde) — cura PlayerProgress.Heal(1) a cada intervalo.
/// - Imunidade a Correntes (Bolha de Coral) — ver <see cref="IsCurrentImmune"/>,
///   consultado por WaterMotor2D/WaterCurrentZone.
/// - Impulso Vertical (Incenso do Vento) — aplicado instantaneamente ao Rigidbody2D.
/// - Destacar Coleccionáveis (Luz de Gaia) — chama PickupBase.SetHighlighted
///   nos coleccionáveis próximos.
///
/// Raiz de Aderência (ConsumableEffectType.Aderencia) NÃO passa por aqui —
/// continua a usar PlayerCombat.ApplyTemporaryGripBuff directamente (Tarefa
/// #28), chamado por PlayerItemUser. Itens em área sobre inimigos (Sono,
/// Resina, Congelamento, e o "perde-alvo" do Pó Dourado) também não passam por
/// aqui — continuam via PlayerItemUser → EnemyStatusEffectReceiver.ApplyItem.
///
/// Todos os temporizadores usam Time.deltaTime, pelo que pausam automaticamente
/// com Time.timeScale = 0 (menus/diálogos — GamePauseUtil). Reaplicar o mesmo
/// tipo de efeito RENOVA a duração em vez de empilhar.
///
/// <see cref="ClearAll"/> remove todos os efeitos activos — chamado
/// automaticamente ao mudar de área (WorldState.CurrentAreaChanged) e ao
/// morrer (PlayerDeathHandler). Sistemas futuros (ex: reinício de desafios)
/// podem chamar isto directamente.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class PlayerConsumableEffects : MonoBehaviour
{
    /// <summary>Singleton simples (1 player) — ver PlayerHealthRegen/PlayerConsumableEffects para o mesmo padrão.</summary>
    public static PlayerConsumableEffects Instance { get; private set; }

    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    // Buffer NonAlloc reutilizável para StartHighlight — evita alocação por uso de item.
    private static readonly Collider2D[] _highlightBuffer = new Collider2D[32];

    // ---- Escudo (Casca Serenna) ----
    private bool _shieldActive;
    private bool _shieldHasTimeLimit;
    private float _shieldTimer;
    private bool _shieldIgnoresSpecialDeaths;

    // ---- Velocidade (Orvalho Veloz) ----
    private float _speedBoostTimer;

    // ---- Invisibilidade (Pó Dourado) ----
    private float _invisibilityTimer;

    // ---- Regeneração (Néctar Verde) ----
    private int _regenHeartsRemaining;
    private float _regenInterval;
    private float _regenTimer;

    // ---- Imunidade a Correntes (Bolha de Coral) ----
    private float _currentImmunityTimer;

    // ---- Destacar Coleccionáveis (Luz de Gaia) ----
    private float _highlightTimer;

    // Item activo por tipo de efeito (para tocar effectEndSfx ao terminar) e
    // VFX instanciado por tipo de efeito (renovado ao reaplicar).
    private readonly Dictionary<ConsumableEffectType, ItemData> _activeItems = new Dictionary<ConsumableEffectType, ItemData>();
    private readonly Dictionary<ConsumableEffectType, GameObject> _activeVfx = new Dictionary<ConsumableEffectType, GameObject>();

    /// <summary>True enquanto o escudo da Casca Serenna estiver activo (ainda não bloqueou um golpe nem expirou).</summary>
    public bool IsShieldActive => _shieldActive;

    /// <summary>True enquanto a invisibilidade do Pó Dourado estiver activa.</summary>
    public bool IsInvisible => _invisibilityTimer > 0f;

    /// <summary>True enquanto a imunidade a correntes da Bolha de Coral estiver activa.</summary>
    public bool IsCurrentImmune => _currentImmunityTimer > 0f;

    private void Awake()
    {
        Instance = this;
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    private void OnEnable()
    {
        if (WorldState.Instance != null) WorldState.Instance.CurrentAreaChanged += OnAreaChanged;
    }

    private void OnDisable()
    {
        if (WorldState.Instance != null) WorldState.Instance.CurrentAreaChanged -= OnAreaChanged;
    }

    /// <summary>Sair da área actual remove todos os efeitos temporários activos.</summary>
    private void OnAreaChanged(AreaData _) => ClearAll();

    private void Update()
    {
        UpdateShield();
        UpdateSpeedBoost();
        UpdateInvisibility();
        UpdateRegen();
        UpdateCurrentImmunity();
        UpdateHighlight();
    }

    /// <summary>
    /// Aplica o efeito pré-programado de "item" (ConsumableEffectType != Nenhum/
    /// Aderencia). Reaplicar o mesmo tipo de efeito renova a duração. Devolve
    /// false se o tipo de efeito não for tratado aqui (Nenhum, Aderencia, ou
    /// efeitos em área sobre inimigos).
    /// </summary>
    public bool ApplyEffect(ItemData item)
    {
        if (item == null) return false;

        switch (item.effectType)
        {
            case ConsumableEffectType.Escudo: StartShield(item); return true;
            case ConsumableEffectType.Velocidade: StartSpeedBoost(item); return true;
            case ConsumableEffectType.Invisibilidade: StartInvisibility(item); return true;
            case ConsumableEffectType.Regeneracao: StartRegen(item); return true;
            case ConsumableEffectType.ImunidadeCorrente: StartCurrentImmunity(item); return true;
            case ConsumableEffectType.ImpulsoVertical: ApplyWindBurst(item); return true;
            case ConsumableEffectType.DestacarColecionaveis: StartHighlight(item); return true;
            default: return false;
        }
    }

    // ---------------- Escudo (Casca Serenna) ----------------

    private void StartShield(ItemData item)
    {
        _shieldActive = true;
        _shieldHasTimeLimit = item.shieldMaxDuration > 0f;
        _shieldTimer = item.shieldMaxDuration;
        _shieldIgnoresSpecialDeaths = item.shieldIgnoresSpecialDeaths;
        PlayStartFeedback(item);
    }

    private void UpdateShield()
    {
        if (!_shieldActive || !_shieldHasTimeLimit) return;

        _shieldTimer -= Time.deltaTime;
        if (_shieldTimer <= 0f) EndShield(playEndSfx: true);
    }

    private void EndShield(bool playEndSfx)
    {
        if (!_shieldActive) return;

        _shieldActive = false;
        DestroyVfx(ConsumableEffectType.Escudo);
        if (playEndSfx) PlayEndSfx(ConsumableEffectType.Escudo);
        else _activeItems.Remove(ConsumableEffectType.Escudo);
    }

    /// <summary>
    /// Chamado por PlayerCombat.TryDamagePlayer quando um golpe causaria dano
    /// (finalAmount &gt; 0, depois de Defesa/ShellGuard). Se o escudo estiver
    /// activo, consome-o e devolve true (bloqueia dano E knockback do golpe).
    /// "isSpecialDeath" (DamageInfo.IgnoreDefense) — se
    /// <see cref="ItemData.shieldIgnoresSpecialDeaths"/> estiver activo no item
    /// que concedeu o escudo, este NÃO bloqueia mortes especiais.
    /// </summary>
    public bool TryConsumeShield(bool isSpecialDeath)
    {
        if (!_shieldActive) return false;
        if (isSpecialDeath && _shieldIgnoresSpecialDeaths) return false;

        EndShield(playEndSfx: true);
        return true;
    }

    // ---------------- Velocidade (Orvalho Veloz) ----------------

    private void StartSpeedBoost(ItemData item)
    {
        motor.SetSpeedMultiplier(item.speedBoostMultiplier);
        _speedBoostTimer = item.speedBoostDuration;
        PlayStartFeedback(item);
    }

    private void UpdateSpeedBoost()
    {
        if (_speedBoostTimer <= 0f) return;

        _speedBoostTimer -= Time.deltaTime;
        if (_speedBoostTimer <= 0f) EndSpeedBoost();
    }

    private void EndSpeedBoost()
    {
        motor.SetSpeedMultiplier(1f);
        DestroyVfx(ConsumableEffectType.Velocidade);
        PlayEndSfx(ConsumableEffectType.Velocidade);
    }

    // ---------------- Invisibilidade (Pó Dourado) ----------------

    private void StartInvisibility(ItemData item)
    {
        _invisibilityTimer = item.invisibilityDuration;
        PlayStartFeedback(item);
    }

    private void UpdateInvisibility()
    {
        if (_invisibilityTimer <= 0f) return;

        _invisibilityTimer -= Time.deltaTime;
        if (_invisibilityTimer <= 0f)
        {
            DestroyVfx(ConsumableEffectType.Invisibilidade);
            PlayEndSfx(ConsumableEffectType.Invisibilidade);
        }
    }

    // ---------------- Regeneração (Néctar Verde) ----------------

    private void StartRegen(ItemData item)
    {
        _regenHeartsRemaining = Mathf.Max(1, item.regenHearts);
        _regenInterval = Mathf.Max(0.01f, item.regenDuration) / _regenHeartsRemaining;
        _regenTimer = _regenInterval;
        PlayStartFeedback(item);
    }

    private void UpdateRegen()
    {
        if (_regenHeartsRemaining <= 0) return;

        _regenTimer -= Time.deltaTime;
        if (_regenTimer > 0f) return;

        PlayerProgress.Instance?.Heal(1);
        _regenHeartsRemaining--;
        _regenTimer = _regenInterval;

        if (_regenHeartsRemaining <= 0)
        {
            DestroyVfx(ConsumableEffectType.Regeneracao);
            PlayEndSfx(ConsumableEffectType.Regeneracao);
        }
    }

    // ---------------- Imunidade a Correntes (Bolha de Coral) ----------------

    private void StartCurrentImmunity(ItemData item)
    {
        _currentImmunityTimer = item.currentImmunityDuration;
        PlayStartFeedback(item);
    }

    private void UpdateCurrentImmunity()
    {
        if (_currentImmunityTimer <= 0f) return;

        _currentImmunityTimer -= Time.deltaTime;
        if (_currentImmunityTimer <= 0f)
        {
            DestroyVfx(ConsumableEffectType.ImunidadeCorrente);
            PlayEndSfx(ConsumableEffectType.ImunidadeCorrente);
        }
    }

    // ---------------- Impulso Vertical (Incenso do Vento) ----------------

    /// <summary>Aplica o impulso vertical instantaneamente: substitui a velocidade vertical actual se for menor que windBurstForce.</summary>
    private void ApplyWindBurst(ItemData item)
    {
        if (rb != null)
            rb.velocity = new Vector2(rb.velocity.x, Mathf.Max(rb.velocity.y, item.windBurstForce));

        PlayStartFeedback(item);

        // VFX instantâneo: não fica "activo" indefinidamente, remover depois de alguns segundos.
        if (_activeVfx.TryGetValue(ConsumableEffectType.ImpulsoVertical, out var vfx) && vfx != null)
            Destroy(vfx, 2f);

        _activeItems.Remove(ConsumableEffectType.ImpulsoVertical);
    }

    // ---------------- Destacar Coleccionáveis (Luz de Gaia) ----------------

    private void StartHighlight(ItemData item)
    {
        _highlightTimer = item.highlightDuration;
        PlayStartFeedback(item);

        int count = Physics2D.OverlapCircleNonAlloc(transform.position, item.highlightRadius, _highlightBuffer);
        for (int i = 0; i < count; i++)
        {
            var pickup = _highlightBuffer[i].GetComponent<PickupBase>();
            if (pickup == null || pickup.Collected) continue;

            if (item.highlightedPickupTypes != null && item.highlightedPickupTypes.Count > 0
                && !item.highlightedPickupTypes.Contains(pickup.Type))
                continue;

            pickup.SetHighlighted(item.highlightColor, item.highlightDuration);
        }
    }

    private void UpdateHighlight()
    {
        if (_highlightTimer <= 0f) return;

        _highlightTimer -= Time.deltaTime;
        if (_highlightTimer <= 0f)
            PlayEndSfx(ConsumableEffectType.DestacarColecionaveis);
    }

    // ---------------- Feedback / Limpeza ----------------

    private void PlayStartFeedback(ItemData item)
    {
        _activeItems[item.effectType] = item;
        AudioManager.Instance?.PlaySE(item.effectActivateSfx);
        SpawnVfx(item);
    }

    private void PlayEndSfx(ConsumableEffectType type)
    {
        if (_activeItems.TryGetValue(type, out var item) && item != null)
            AudioManager.Instance?.PlaySE(item.effectEndSfx);

        _activeItems.Remove(type);
    }

    private void SpawnVfx(ItemData item)
    {
        DestroyVfx(item.effectType);
        if (item.effectVfxPrefab == null) return;

        _activeVfx[item.effectType] = Instantiate(item.effectVfxPrefab, transform.position, Quaternion.identity, transform);
    }

    private void DestroyVfx(ConsumableEffectType type)
    {
        if (_activeVfx.TryGetValue(type, out var vfx) && vfx != null) Destroy(vfx);
        _activeVfx.Remove(type);
    }

    /// <summary>
    /// Remove TODOS os efeitos activos imediatamente (sem tocar effectEndSfx):
    /// chamado ao mudar de área e ao morrer. Sistemas futuros (ex: reinício de
    /// desafio) podem chamar isto directamente.
    /// </summary>
    public void ClearAll()
    {
        if (_shieldActive) EndShield(playEndSfx: false);

        if (_speedBoostTimer > 0f)
        {
            motor.SetSpeedMultiplier(1f);
            _speedBoostTimer = 0f;
        }

        _invisibilityTimer = 0f;
        _regenHeartsRemaining = 0;
        _currentImmunityTimer = 0f;
        _highlightTimer = 0f;

        foreach (var vfx in _activeVfx.Values)
            if (vfx != null) Destroy(vfx);

        _activeVfx.Clear();
        _activeItems.Clear();
    }
}
